import{_ as t,H as n,f as s,i as e}from"./chunks/framework.BHvCMIhP.js";const c=JSON.parse('{"title":"算法选型手册与面试实战","description":"","frontmatter":{},"headers":[],"relativePath":"algorithmLearning/28-算法选型手册与面试实战.md","filePath":"algorithmLearning/28-算法选型手册与面试实战.md","lastUpdated":1778496697000}'),o={name:"algorithmLearning/28-算法选型手册与面试实战.md"};function r(i,a,l,p,d,h){return n(),s("div",null,[...a[0]||(a[0]=[e(`<h1 id="算法选型手册与面试实战" tabindex="-1">算法选型手册与面试实战 <a class="header-anchor" href="#算法选型手册与面试实战" aria-label="Permalink to &quot;算法选型手册与面试实战&quot;">​</a></h1><p>最后一篇,把前 27 篇内容浓缩成一张**&quot;看到题怎么想&quot;** 的心智地图。这不是知识点总结,是<strong>面试和工程实战时直接调用的查找表</strong>——遇到陌生题,你的大脑该按什么路径检索答案。</p><blockquote><p>一句话先记住:<strong>算法解题 = 识别模式 → 选数据结构 → 套范式模板</strong>。会模式识别是 L2,会模板是 L1,<strong>两个不会就是 L0</strong>。这一篇专门训练&quot;模式识别&quot;——给关键词,直接弹出&quot;这是什么类型的题&quot;。</p></blockquote><hr><h2 id="一、信号词-→-算法类型-速查表" tabindex="-1">一、信号词 → 算法类型 速查表 <a class="header-anchor" href="#一、信号词-→-算法类型-速查表" aria-label="Permalink to &quot;一、信号词 → 算法类型 速查表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>题里出现</th><th>大概率是</th></tr></thead><tbody><tr><td>&quot;最长 / 最短子串 / 子数组&quot;</td><td><strong>滑动窗口</strong> 或 <strong>DP</strong></td></tr><tr><td>&quot;最长 / 最大 / 最小&quot; + &quot;递增 / 路径&quot;</td><td><strong>DP</strong></td></tr><tr><td>&quot;所有方案 / 所有排列 / 所有组合&quot;</td><td><strong>回溯</strong></td></tr><tr><td>&quot;第 K 大 / 第 K 小&quot;</td><td><strong>快速选择 / 堆</strong></td></tr><tr><td>&quot;Top K&quot;</td><td><strong>小根堆</strong>(取最大 K)</td></tr><tr><td>&quot;下一个更大 / 更小&quot;</td><td><strong>单调栈</strong></td></tr><tr><td>&quot;滑动窗口最值&quot;</td><td><strong>单调队列</strong></td></tr><tr><td>&quot;判存在 / 去重 / 计数&quot;</td><td><strong>哈希表 / Set</strong></td></tr><tr><td>&quot;前缀 / 自动补全 / 字符串集合&quot;</td><td><strong>Trie</strong></td></tr><tr><td>&quot;动态连通性 / 分组&quot;</td><td><strong>并查集</strong></td></tr><tr><td>&quot;最短路径(无权)&quot;</td><td><strong>BFS</strong></td></tr><tr><td>&quot;最短路径(正权)&quot;</td><td><strong>Dijkstra + 堆</strong></td></tr><tr><td>&quot;依赖排序 / 上课顺序 / 编译顺序&quot;</td><td><strong>拓扑排序</strong></td></tr><tr><td>&quot;有序数组找位置 / 边界&quot;</td><td><strong>二分</strong></td></tr><tr><td>&quot;最大化最小 / 最小化最大&quot;</td><td><strong>二分答案</strong></td></tr><tr><td>&quot;成对出现 / 区间和 / 反转&quot;</td><td><strong>双指针</strong></td></tr><tr><td>&quot;随机选 / 等概率&quot;</td><td><strong>水库抽样</strong></td></tr><tr><td>&quot;区间合并 / 区间安排&quot;</td><td><strong>排序 + 贪心</strong></td></tr><tr><td>&quot;凑硬币 / 背包 / 子集和&quot;</td><td><strong>DP / 完全背包</strong></td></tr><tr><td>&quot;状态压缩 / 集合 ≤ 20&quot;</td><td><strong>状压 DP</strong></td></tr><tr><td>&quot;树的路径 / 子树&quot;</td><td><strong>DFS + 后序</strong></td></tr></tbody></table><p><strong>这张表背下来,80% 的题在 30 秒内能&quot;分类&quot;</strong> —— 分类准了,套路就有了。</p><hr><h2 id="二、按数据范围反推算法" tabindex="-1">二、按数据范围反推算法 <a class="header-anchor" href="#二、按数据范围反推算法" aria-label="Permalink to &quot;二、按数据范围反推算法&quot;">​</a></h2><table tabindex="0"><thead><tr><th>n 范围</th><th>允许的复杂度</th><th>算法候选</th></tr></thead><tbody><tr><td>n ≤ 10</td><td>O(n!)</td><td>全排列 / 暴力回溯</td></tr><tr><td>n ≤ 20</td><td>O(2ⁿ · n)</td><td>状压 DP / 子集枚举</td></tr><tr><td>n ≤ 100</td><td>O(n⁴)</td><td>三维 DP / 区间 DP</td></tr><tr><td>n ≤ 500</td><td>O(n³)</td><td>Floyd / 区间 DP</td></tr><tr><td>n ≤ 5000</td><td>O(n²)</td><td>双层循环 / DP</td></tr><tr><td>n ≤ 10⁶</td><td>O(n log n)</td><td>排序 / 堆 / 二分</td></tr><tr><td>n ≤ 10⁸</td><td>O(n)</td><td>双指针 / 滑窗 / 哈希</td></tr><tr><td>n &gt; 10⁸</td><td>O(log n) / O(1)</td><td>二分 / 数学 / 矩阵快速幂</td></tr></tbody></table><p><strong>先看 n,再选算法</strong>——n 给了你一个&quot;算法上限&quot;。 <strong>面试拿到题先问输入范围</strong>,不是装内行,<strong>是真的在做工程判断</strong>。</p><hr><h2 id="三、按-输入特征-选数据结构" tabindex="-1">三、按&quot;输入特征&quot;选数据结构 <a class="header-anchor" href="#三、按-输入特征-选数据结构" aria-label="Permalink to &quot;三、按&quot;输入特征&quot;选数据结构&quot;">​</a></h2><h3 id="_1-数据是数字-范围小" tabindex="-1">1. 数据是数字 + 范围小 <a class="header-anchor" href="#_1-数据是数字-范围小" aria-label="Permalink to &quot;1. 数据是数字 + 范围小&quot;">​</a></h3><p>→ <strong>数组 / 计数排序 / 桶排序</strong></p><h3 id="_2-数据是字符串-长度长" tabindex="-1">2. 数据是字符串 + 长度长 <a class="header-anchor" href="#_2-数据是字符串-长度长" aria-label="Permalink to &quot;2. 数据是字符串 + 长度长&quot;">​</a></h3><p>→ <strong>KMP / Trie / Rabin-Karp / 后缀数组</strong></p><h3 id="_3-数据是流式" tabindex="-1">3. 数据是流式 <a class="header-anchor" href="#_3-数据是流式" aria-label="Permalink to &quot;3. 数据是流式&quot;">​</a></h3><p>→ <strong>滑窗 / 蓄水池 / Count-Min Sketch / HyperLogLog</strong></p><h3 id="_4-数据是有序的" tabindex="-1">4. 数据是有序的 <a class="header-anchor" href="#_4-数据是有序的" aria-label="Permalink to &quot;4. 数据是有序的&quot;">​</a></h3><p>→ <strong>二分 / 双指针</strong></p><h3 id="_5-数据是图-树" tabindex="-1">5. 数据是图 / 树 <a class="header-anchor" href="#_5-数据是图-树" aria-label="Permalink to &quot;5. 数据是图 / 树&quot;">​</a></h3><p>→ <strong>BFS / DFS / 并查集 / 树 DP</strong></p><h3 id="_6-数据有-区间-概念" tabindex="-1">6. 数据有&quot;区间&quot;概念 <a class="header-anchor" href="#_6-数据有-区间-概念" aria-label="Permalink to &quot;6. 数据有&quot;区间&quot;概念&quot;">​</a></h3><p>→ <strong>排序 + 贪心 / 前缀和 / 差分 / 线段树</strong></p><h3 id="_7-数据要-实时第-k-大" tabindex="-1">7. 数据要&quot;实时第 K 大&quot; <a class="header-anchor" href="#_7-数据要-实时第-k-大" aria-label="Permalink to &quot;7. 数据要&quot;实时第 K 大&quot;&quot;">​</a></h3><p>→ <strong>堆 / 平衡 BST / 双堆</strong></p><hr><h2 id="四、八大经典模板速记" tabindex="-1">四、八大经典模板速记 <a class="header-anchor" href="#四、八大经典模板速记" aria-label="Permalink to &quot;四、八大经典模板速记&quot;">​</a></h2><h3 id="模板-1-滑动窗口-变长" tabindex="-1">模板 1:滑动窗口(变长) <a class="header-anchor" href="#模板-1-滑动窗口-变长" aria-label="Permalink to &quot;模板 1:滑动窗口(变长)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>left = 0, ans = 0</span></span>
<span class="line"><span>for right in range:</span></span>
<span class="line"><span>    扩大窗口(把 right 加进来)</span></span>
<span class="line"><span>    while 窗口违反条件:</span></span>
<span class="line"><span>        缩小窗口(把 left 移出去)</span></span>
<span class="line"><span>        left++</span></span>
<span class="line"><span>    更新答案</span></span></code></pre></div><h3 id="模板-2-二分-红蓝染色" tabindex="-1">模板 2:二分(红蓝染色) <a class="header-anchor" href="#模板-2-二分-红蓝染色" aria-label="Permalink to &quot;模板 2:二分(红蓝染色)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>lo = 0, hi = n</span></span>
<span class="line"><span>while lo &lt; hi:</span></span>
<span class="line"><span>    mid = (lo + hi) &gt;&gt; 1</span></span>
<span class="line"><span>    if check(mid): hi = mid     # 红色</span></span>
<span class="line"><span>    else: lo = mid + 1           # 蓝色</span></span>
<span class="line"><span>return lo</span></span></code></pre></div><h3 id="模板-3-回溯" tabindex="-1">模板 3:回溯 <a class="header-anchor" href="#模板-3-回溯" aria-label="Permalink to &quot;模板 3:回溯&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>function bt(path, start):</span></span>
<span class="line"><span>    if 满足结束: result.push([...path]); return</span></span>
<span class="line"><span>    for choice in choices(start):</span></span>
<span class="line"><span>        if 不合法: continue</span></span>
<span class="line"><span>        path.push(choice)</span></span>
<span class="line"><span>        bt(path, next_start)</span></span>
<span class="line"><span>        path.pop()</span></span></code></pre></div><h3 id="模板-4-dfs-树" tabindex="-1">模板 4:DFS(树) <a class="header-anchor" href="#模板-4-dfs-树" aria-label="Permalink to &quot;模板 4:DFS(树)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>function dfs(node):</span></span>
<span class="line"><span>    if !node: return baseCase</span></span>
<span class="line"><span>    left = dfs(node.left)</span></span>
<span class="line"><span>    right = dfs(node.right)</span></span>
<span class="line"><span>    return combine(node, left, right)</span></span></code></pre></div><h3 id="模板-5-bfs-图" tabindex="-1">模板 5:BFS(图) <a class="header-anchor" href="#模板-5-bfs-图" aria-label="Permalink to &quot;模板 5:BFS(图)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>queue = [start]</span></span>
<span class="line"><span>visited.add(start)</span></span>
<span class="line"><span>while queue:</span></span>
<span class="line"><span>    size = queue.length</span></span>
<span class="line"><span>    for i in size:</span></span>
<span class="line"><span>        node = queue.shift()</span></span>
<span class="line"><span>        for next in neighbors(node):</span></span>
<span class="line"><span>            if next not in visited:</span></span>
<span class="line"><span>                visited.add(next)</span></span>
<span class="line"><span>                queue.push(next)</span></span></code></pre></div><h3 id="模板-6-dp-自底向上" tabindex="-1">模板 6:DP(自底向上) <a class="header-anchor" href="#模板-6-dp-自底向上" aria-label="Permalink to &quot;模板 6:DP(自底向上)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dp = array of base values</span></span>
<span class="line"><span>for i in range:</span></span>
<span class="line"><span>    for state transition:</span></span>
<span class="line"><span>        dp[i] = combine(dp[smaller])</span></span>
<span class="line"><span>return dp[n]</span></span></code></pre></div><h3 id="模板-7-并查集" tabindex="-1">模板 7:并查集 <a class="header-anchor" href="#模板-7-并查集" aria-label="Permalink to &quot;模板 7:并查集&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>parent = [i for i in range(n)]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>function find(x):</span></span>
<span class="line"><span>    if parent[x] != x: parent[x] = find(parent[x])</span></span>
<span class="line"><span>    return parent[x]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>function union(a, b):</span></span>
<span class="line"><span>    parent[find(a)] = find(b)</span></span></code></pre></div><h3 id="模板-8-拓扑排序-kahn" tabindex="-1">模板 8:拓扑排序(Kahn) <a class="header-anchor" href="#模板-8-拓扑排序-kahn" aria-label="Permalink to &quot;模板 8:拓扑排序(Kahn)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>inDeg = count incoming edges for each node</span></span>
<span class="line"><span>queue = nodes with inDeg == 0</span></span>
<span class="line"><span>result = []</span></span>
<span class="line"><span>while queue:</span></span>
<span class="line"><span>    node = queue.shift()</span></span>
<span class="line"><span>    result.push(node)</span></span>
<span class="line"><span>    for next in node&#39;s edges:</span></span>
<span class="line"><span>        inDeg[next]--</span></span>
<span class="line"><span>        if inDeg[next] == 0: queue.push(next)</span></span>
<span class="line"><span>return result if length == n else &quot;有环&quot;</span></span></code></pre></div><p><strong>这八个模板倒背如流</strong>,你已经能搞定面试 70% 的算法题。</p><hr><h2 id="五、面试时的标准流程" tabindex="-1">五、面试时的标准流程 <a class="header-anchor" href="#五、面试时的标准流程" aria-label="Permalink to &quot;五、面试时的标准流程&quot;">​</a></h2><h3 id="第一步-复述问题-30-秒" tabindex="-1">第一步:复述问题(30 秒) <a class="header-anchor" href="#第一步-复述问题-30-秒" aria-label="Permalink to &quot;第一步:复述问题(30 秒)&quot;">​</a></h3><p>&quot;我理解一下,题目是说……对吗?&quot; <strong>避免一开始就跑偏</strong>。</p><h3 id="第二步-问输入范围-15-秒" tabindex="-1">第二步:问输入范围(15 秒) <a class="header-anchor" href="#第二步-问输入范围-15-秒" aria-label="Permalink to &quot;第二步:问输入范围(15 秒)&quot;">​</a></h3><p>&quot;n 大概多大?数据是什么类型?有特殊约束吗?&quot; <strong>输入范围决定算法选择,这是工程师本能</strong>。</p><h3 id="第三步-举例-1-分钟" tabindex="-1">第三步:举例(1 分钟) <a class="header-anchor" href="#第三步-举例-1-分钟" aria-label="Permalink to &quot;第三步:举例(1 分钟)&quot;">​</a></h3><p>&quot;我用一个小例子走一遍。比如……&quot; <strong>自己走例子能发现 50% 的边界 case</strong>。</p><h3 id="第四步-暴力解-1-分钟" tabindex="-1">第四步:暴力解(1 分钟) <a class="header-anchor" href="#第四步-暴力解-1-分钟" aria-label="Permalink to &quot;第四步:暴力解(1 分钟)&quot;">​</a></h3><p>&quot;我先想一个朴素解法是这样,复杂度 O(...),不过我觉得能优化&quot; <strong>永远先报朴素解</strong>——给面试官信号&quot;我能解出来,只是想得更优&quot;。</p><h3 id="第五步-优化-2-3-分钟" tabindex="-1">第五步:优化(2-3 分钟) <a class="header-anchor" href="#第五步-优化-2-3-分钟" aria-label="Permalink to &quot;第五步:优化(2-3 分钟)&quot;">​</a></h3><p>&quot;想优化的话,可以用 ... 把它降到 O(...)&quot; <strong>展示思路</strong>,而不是直接写代码。</p><h3 id="第六步-写代码-5-10-分钟" tabindex="-1">第六步:写代码(5-10 分钟) <a class="header-anchor" href="#第六步-写代码-5-10-分钟" aria-label="Permalink to &quot;第六步:写代码(5-10 分钟)&quot;">​</a></h3><p>边写边讲。<strong>注释每个关键步骤</strong>。</p><h3 id="第七步-测试-2-分钟" tabindex="-1">第七步:测试(2 分钟) <a class="header-anchor" href="#第七步-测试-2-分钟" aria-label="Permalink to &quot;第七步:测试(2 分钟)&quot;">​</a></h3><p>&quot;我跑一下边界 case……空输入,单元素,极大输入。&quot; <strong>主动找 bug,比让面试官找好</strong>。</p><h3 id="第八步-复杂度" tabindex="-1">第八步:复杂度 <a class="header-anchor" href="#第八步-复杂度" aria-label="Permalink to &quot;第八步:复杂度&quot;">​</a></h3><p>&quot;时间 O(...),空间 O(...)&quot;。</p><p><strong>这八步流水线下来,即使没做出来,面试官也能给你一个&quot;思路清晰&quot;的评价</strong>。</p><hr><h2 id="六、常见反模式" tabindex="-1">六、常见反模式 <a class="header-anchor" href="#六、常见反模式" aria-label="Permalink to &quot;六、常见反模式&quot;">​</a></h2><h3 id="反模式-1-闷头写" tabindex="-1">反模式 1:闷头写 <a class="header-anchor" href="#反模式-1-闷头写" aria-label="Permalink to &quot;反模式 1:闷头写&quot;">​</a></h3><p>不沟通直接埋头。<strong>面试不是写代码考试,是沟通考试</strong>。</p><h3 id="反模式-2-先纠结边界" tabindex="-1">反模式 2:先纠结边界 <a class="header-anchor" href="#反模式-2-先纠结边界" aria-label="Permalink to &quot;反模式 2:先纠结边界&quot;">​</a></h3><p><code>i &lt;= n</code> 还是 <code>i &lt; n</code> 想 5 分钟。<strong>先写大方向,边界后补</strong>。</p><h3 id="反模式-3-不画图" tabindex="-1">反模式 3:不画图 <a class="header-anchor" href="#反模式-3-不画图" aria-label="Permalink to &quot;反模式 3:不画图&quot;">​</a></h3><p>链表 / 树 / 图题不画图,纯靠脑子想。<strong>画图能省 50% 思考时间</strong>。</p><h3 id="反模式-4-不报朴素解" tabindex="-1">反模式 4:不报朴素解 <a class="header-anchor" href="#反模式-4-不报朴素解" aria-label="Permalink to &quot;反模式 4:不报朴素解&quot;">​</a></h3><p>直接憋&quot;最优解&quot;,憋不出来就交白卷。<strong>朴素解是保底,先有解再优化</strong>。</p><h3 id="反模式-5-抗拒提示" tabindex="-1">反模式 5:抗拒提示 <a class="header-anchor" href="#反模式-5-抗拒提示" aria-label="Permalink to &quot;反模式 5:抗拒提示&quot;">​</a></h3><p>面试官给提示了还坚持自己思路。<strong>提示是免费的方向修正</strong>,接受它。</p><hr><h2 id="七、最值得花时间的-10-个模板" tabindex="-1">七、最值得花时间的 10 个模板 <a class="header-anchor" href="#七、最值得花时间的-10-个模板" aria-label="Permalink to &quot;七、最值得花时间的 10 个模板&quot;">​</a></h2><p>按 ROI 从高到低排:</p><ol><li><strong>滑动窗口(变长)</strong> —— 字符串 / 数组高频</li><li><strong>二分(红蓝模板)</strong> —— 一次写对终身受用</li><li><strong>DFS 模板</strong> —— 树 / 图无脑套</li><li><strong>BFS 模板</strong> —— 最短路径必备</li><li><strong>回溯模板</strong> —— 所有&quot;列举所有方案&quot;题</li><li><strong>DP 状态定义</strong> —— 知道往哪想</li><li><strong>单调栈模板</strong> —— &quot;下一个更大&quot;专用</li><li><strong>并查集模板</strong> —— 30 行代码超高 ROI</li><li><strong>快慢指针</strong> —— 链表题套路</li><li><strong>堆 + 优先队列用法</strong> —— Top K 杀手</li></ol><p><strong>优先把这 10 个练到 5 分钟内能写出</strong>,面试通过率会显著提升。</p><hr><h2 id="八、工程师视角的-不重要的" tabindex="-1">八、工程师视角的&quot;不重要的&quot; <a class="header-anchor" href="#八、工程师视角的-不重要的" aria-label="Permalink to &quot;八、工程师视角的&quot;不重要的&quot;&quot;">​</a></h2><p>LeetCode 上有但工程少见,可以<strong>优先级低</strong>:</p><ul><li>后缀数组 / 后缀自动机</li><li>莫队算法 / 分块</li><li>树链剖分</li><li>KMP 的失配函数 next 数组细节(理解就行,工程基本不写)</li><li>复杂的位运算技巧</li><li>数论(费马小定理 / 莫比乌斯反演)</li></ul><p><strong>这些是 ACM / 竞赛级</strong>,后端 / 前端 / 全栈面试基本不考。<strong>别在这上面花太多时间</strong>,优先把上面的 10 个模板练熟。</p><hr><h2 id="九、坚持训练的方法" tabindex="-1">九、坚持训练的方法 <a class="header-anchor" href="#九、坚持训练的方法" aria-label="Permalink to &quot;九、坚持训练的方法&quot;">​</a></h2><h3 id="_1-按套路分组刷-不按编号" tabindex="-1">1. 按套路分组刷,不按编号 <a class="header-anchor" href="#_1-按套路分组刷-不按编号" aria-label="Permalink to &quot;1. 按套路分组刷,不按编号&quot;">​</a></h3><p>刷 10 道滑窗连着刷,不要今天滑窗、明天 DP、后天图。<strong>集中刷一个套路才能形成肌肉记忆</strong>。</p><h3 id="_2-每道题写-复盘笔记" tabindex="-1">2. 每道题写&quot;复盘笔记&quot; <a class="header-anchor" href="#_2-每道题写-复盘笔记" aria-label="Permalink to &quot;2. 每道题写&quot;复盘笔记&quot;&quot;">​</a></h3><p>题号 + 类型 + 套路 + 复杂度 + 一句话核心思路。<strong>积累 100 道题的笔记 = 你的私人查找表</strong>。</p><h3 id="_3-一周回顾一次" tabindex="-1">3. 一周回顾一次 <a class="header-anchor" href="#_3-一周回顾一次" aria-label="Permalink to &quot;3. 一周回顾一次&quot;">​</a></h3><p>把上周做的题<strong>关电脑默写一遍</strong>。能默写出来才算真会。</p><h3 id="_4-模拟面试" tabindex="-1">4. 模拟面试 <a class="header-anchor" href="#_4-模拟面试" aria-label="Permalink to &quot;4. 模拟面试&quot;">​</a></h3><p>跟同行 mock。<strong>有人盯着你写代码</strong> 是另一种能力。</p><hr><h2 id="十、本系列的最后一句" tabindex="-1">十、本系列的最后一句 <a class="header-anchor" href="#十、本系列的最后一句" aria-label="Permalink to &quot;十、本系列的最后一句&quot;">​</a></h2><blockquote><p>28 篇看完,你应该不再&quot;看到题就懵&quot;——而是脑子里能浮起 3 个候选模式,然后比对最像哪个。<strong>这就是从 L1 到 L2 的跨越</strong>。</p></blockquote><blockquote><p>算法不是终极目标,<strong>它是工程师的&quot;基本功&quot;</strong> —— 像武术里的扎马步。会扎马步不代表你会打架,但<strong>不会扎马步就别指望打赢</strong>。系统设计 / 后端 / 分布式都建立在算法基础上,基础不稳,上层全是空中楼阁。</p></blockquote><blockquote><p>下一站建议:<strong>找一个真实项目,把学到的数据结构和算法用进去</strong>。自己写一个 LRU、自己实现一个限流中间件、自己用一致性哈希做一个分布式 KV——<strong>做出来的&quot;真东西&quot;</strong> 比刷 100 道 LeetCode 强。</p></blockquote><hr><h2 id="完结-2026-05-08" tabindex="-1">完结(2026/05/08) <a class="header-anchor" href="#完结-2026-05-08" aria-label="Permalink to &quot;完结(2026/05/08)&quot;">​</a></h2><p>28 篇全部完成。下一步建议:</p><ul><li>选一个项目带算法实战(限流中间件 / 简易缓存 / URL 短链)</li><li>建立自己的&quot;题型 - 套路&quot;笔记本</li><li>模式识别能力是要在做题中练出来的,<strong>模板背了不练等于没背</strong></li></ul><p>跟其他系列一样,<strong>不熟的题型回头翻对应那篇,出事故时第一反应是&quot;这是哪个套路&quot;,而不是从头硬想</strong>。</p>`,107)])])}const g=t(o,[["render",r]]);export{c as __pageData,g as default};
